CREATE OR REPLACE FUNCTION fpb_get_date_spp_mem_monthly (as_memno char ,adt_dfrom timestamp(0) ,adt_dto timestamp(0) ) RETURNS varchar AS $body$
DECLARE

li_count integer;
ldc_amount  bigint;
ls_return varchar(100);
ls_date varchar(50);
ls_recno varchar(50);
c_receipt CURSOR FOR
  SELECT  receipt_no , receipt_date
  from 		sc_com_m_receipt
  where ( membership_no = as_memno)
  and ( sc_com_m_receipt.receipt_date between adt_dfrom and adt_dto )
  and ( sc_com_m_receipt.receipt_status = '0' )
  and ( sc_com_m_receipt.money_type_id not in ( 'CLR' , 'TNL' ) );

  type tabrowi_data is table of c_receipt%rowtype index by integer;ltabrowi_data tabrowi_data;

BEGIN
  open c_receipt;fetch c_receipt bulk collect into ltabrowi_data;close c_receipt;
  li_count := ltabrowi_data.count;
  for i in 1..li_count loop
    if i > 1 then
      ls_recno := ls_recno ||','|| trim(both ltabrowi_data[i].receipt_no);
      ls_date := ls_date ||','|| pka_com_function.fp_get_thaidate(ltabrowi_data[i].receipt_date,'SD/MM/YYYY');
    else
      ls_recno := trim(both ltabrowi_data[i].receipt_no);
      ls_date := pka_com_function.fp_get_thaidate(ltabrowi_data[i].receipt_date,'SD/MM/YYYY');
    end if;

  end loop;

  if len(trim(both ls_recno)) > 1 then
    ls_return := ls_recno||' / '||ls_date;
  else
    ls_return := ' ';
  end if;
  return  ls_return;
exception when others then return ' ';

end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
